  ('fire-eq-tech-moex-01658', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依防火牆及防火水幕設置基準，防火水幕防護高度為5公尺，防護對象為儲存8000公秉第四類公共危險 物品儲槽，依規定核算其水源容量應在多少立方公尺以上？', '["40", "60", "80", "100"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01659', 'fire-eq-tech', 'fire-eq-tech-moex-105-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依消防設備師及消防設備士管理辦法之規定，消防設備師（士）執行業務，應備有詳細業務登記簿，以 備各級消防機關之查核，並至少應保存幾年？', '["3", "5", "7", "10"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "66510b8ab851", "answer_pdf_sha1": "1780d0ca3689", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
